const subject = $json.subject || '';
const html    = $json.body_text || '';

// Strip HTML — keep table rows / br as line breaks
function strip(s) {
  s = s.replace(/<br[^>]*>/gi, '\n');
  s = s.replace(/<\/(td|th|tr|p|div)\s*>/gi, '\n');
  s = s.replace(/<[^>]+>/g, ' ');
  // Decode common HTML entities
  s = s.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');
  s = s.replace(/[ \t]+/g, ' ').replace(/\n[ \t]*\n/g, '\n');
  return s.trim();
}
const text = strip(html);

// Subject pattern: 'New Reservation  -  agodaycs for John Rowell 657887135_L-1420'
const subjMatch = subject.match(/(New|Cancelled|Modified)\s+Reservation\s+-\s+(\S+)\s+for\s+(.+?)\s+(\S+)$/i);

let status = null, source = null, guest = null, source_ref = null;
if (subjMatch) {
  status     = subjMatch[1].charAt(0).toUpperCase() + subjMatch[1].slice(1).toLowerCase();
  source     = subjMatch[2];
  guest      = subjMatch[3];
  source_ref = subjMatch[4];
} else {
  return { json: { email_id: $json.email_id, parseable: false, reason: 'subject_unparseable', subject } };
}

function grab(re) { const m = text.match(re); return m ? m[1].trim() : null; }

const room       = grab(/Room\s+(.+?)\s+Check\s*in/i);
const dateRange  = grab(/Check\s*in\s+(\d{1,2}\s+\w{3}\s+\d{4}\s*-\s*\d{1,2}\s+\w{3}\s+\d{4})/i);
const mealPlan   = grab(/Meal\s+Plan\s*:\s*(.+?)$/im) || grab(/(Bed\s*&\s*Breakfast|Room\s*Only|Half\s*Board|Full\s*Board)/i);
const adults     = grab(/Adults\s*:?\s*(\d+)/i);
const children   = grab(/Children\s*:?\s*(\d+)/i);
const totalLine  = text.match(/Total\s+(GBP|USD|EUR|\u00a3|\$|\u20ac)\s*([\d,]+(?:\.\d{1,2})?)/i);
const grossLine  = text.match(/(?:Sub[-\s]?total|Gross|Room\s+rate)\s+(GBP|USD|EUR|\u00a3|\$|\u20ac)\s*([\d,]+(?:\.\d{1,2})?)/i);
const commission = text.match(/Commission\s+(?:GBP|USD|EUR|\u00a3|\$|\u20ac)\s*([\d,]+(?:\.\d{1,2})?)/i);
const tax        = text.match(/Tax\s+(?:GBP|USD|EUR|\u00a3|\$|\u20ac)\s*([\d,]+(?:\.\d{1,2})?)/i);

// Parse date range '17 Jun 2026 - 18 Jun 2026'
let checkin = null, checkout = null;
if (dateRange) {
  const parts = dateRange.split('-').map(s => s.trim());
  function toIso(d) {
    const m = d.match(/(\d{1,2})\s+(\w{3})\s+(\d{4})/);
    if (!m) return null;
    const months = { jan:'01', feb:'02', mar:'03', apr:'04', may:'05', jun:'06', jul:'07', aug:'08', sep:'09', oct:'10', nov:'11', dec:'12' };
    const mo = months[m[2].toLowerCase()];
    if (!mo) return null;
    return `${m[3]}-${mo}-${m[1].padStart(2,'0')}`;
  }
  checkin  = toIso(parts[0]);
  checkout = toIso(parts[1]);
}

function n(s) { return s == null ? null : Number(String(s).replace(/,/g, '')); }

const total      = totalLine  ? n(totalLine[2])  : null;
const gross      = grossLine  ? n(grossLine[2])  : total;
const commissionAmt = commission ? n(commission[1]) : null;
const taxAmt     = tax        ? n(tax[1])        : null;

// Currency: take from total line or default GBP
const currency = totalLine ? totalLine[1].toUpperCase().replace('\u00a3', 'GBP').replace('\u20ac', 'EUR').replace('$', 'USD') : 'GBP';

const parseable = !!(status && source && source_ref);

return { json: {
  email_id:        $json.email_id,
  source_event_id: $json.source_event_id,
  source, source_ref, status, guest_name: guest,
  room, checkin_date: checkin, checkout_date: checkout,
  adults: adults ? Number(adults) : null,
  children: children ? Number(children) : null,
  meal_plan: mealPlan,
  currency, gross_amount: gross,
  commission: commissionAmt, tax: taxAmt, total_amount: total,
  raw_text: text.substring(0, 2000),
  parseable,
  subject
} };
